class TestDeepGetHappyPath:
    def test_single_key(self):
        assert deep_get({"a": 1}, "a") == 1

    def test_two_level_nesting(self):
        assert deep_get({"a": {"b": 2}}, "a.b") == 2

    def test_three_level_nesting(self):
        assert deep_get({"a": {"b": {"c": 3}}}, "a.b.c") == 3

    def test_deeply_nested(self):
        d = {"l1": {"l2": {"l3": {"l4": {"l5": "deep"}}}}}
        assert deep_get(d, "l1.l2.l3.l4.l5") == "deep"

    def test_returns_string_value(self):
        assert deep_get({"name": "Alice"}, "name") == "Alice"

    def test_returns_list_value(self):
        assert deep_get({"items": [1, 2, 3]}, "items") == [1, 2, 3]

    def test_returns_dict_value(self):
        inner = {"x": 10}
        assert deep_get({"a": inner}, "a") == inner

    def test_returns_none_value_stored_in_dict(self):
        """None as an actual stored value should be returned, not the default."""
        assert deep_get({"a": None}, "a") is None

    def test_returns_false_value_stored_in_dict(self):
        assert deep_get({"flag": False}, "flag") is False

    def test_returns_zero_value_stored_in_dict(self):
        assert deep_get({"count": 0}, "count") == 0

    def test_returns_empty_string_value(self):
        assert deep_get({"key": ""}, "key") == ""

    def test_returns_nested_list(self):
        d = {"a": {"b": [1, 2, 3]}}
        assert deep_get(d, "a.b") == [1, 2, 3]

    def test_key_with_integer_value(self):
        assert deep_get({"a": {"b": 42}}, "a.b") == 42


